#!/usr/bin/env -S npx ts-node -r tsconfig-paths/register
/**
 * Example: Create a reusable job definition
 *
 * This example demonstrates:
 * - Creating a job definition (without running it)
 * - Configuring job schedule
 * - Setting up notifications
 * - Deleting the job
 *
 * Prerequisites:
 * - DATABRICKS_HOST environment variable
 * - Valid authentication (PAT, OAuth M2M, or other)
 *
 * Usage:
 *   npx ts-node examples/workspace/jobs/create-job.ts
 */

import {WorkspaceClient} from "@databricks/sdk-experimental";

async function main() {
    const client = new WorkspaceClient({});

    const jobName = `sdk-job-example-${Date.now()}`;

    console.log(`Creating job: ${jobName}`);

    try {
        // Create a reusable job definition
        const job = await client.jobs.create({
            name: jobName,
            tasks: [
                {
                    task_key: "data_processing",
                    description: "Process data from source to destination",
                    notebook_task: {
                        notebook_path: "/Shared/data-pipeline", // Adjust path as needed
                        source: "WORKSPACE",
                    },
                    new_cluster: {
                        spark_version: await client.clusters.selectSparkVersion(
                            {latest: true}
                        ),
                        node_type_id: await client.clusters.selectNodeType({
                            minMemoryGb: 8,
                            minCores: 2,
                        }),
                        num_workers: 2,
                        spark_conf: {
                            "spark.speculation": "true",
                        },
                    },
                    timeout_seconds: 3600, // 1 hour timeout
                },
            ],
            // Configure schedule (runs daily at 2 AM)
            schedule: {
                quartz_cron_expression: "0 0 2 * * ?",
                timezone_id: "America/Los_Angeles",
                pause_status: "PAUSED", // Start paused
            },
            // Email notifications on failure
            email_notifications: {
                on_failure: ["your-email@example.com"],
            },
            timeout_seconds: 7200, // 2 hour job timeout
            max_concurrent_runs: 1,
        });

        console.log(`✓ Job created successfully!`);
        console.log(`  Job ID: ${job.job_id}`);
        console.log(`  Job Name: ${jobName}`);
        console.log(`  Job URL: ${client.config.host}#job/${job.job_id}`);
        console.log(`  Schedule: Daily at 2 AM (paused)`);

        // Cleanup: Delete the job
        console.log(`\nCleaning up: deleting job ${job.job_id}`);
        await client.jobs.delete({job_id: job.job_id!});
        console.log(`✓ Job deleted`);
    } catch (error) {
        console.error(`✗ Error:`, error);
        process.exit(1);
    }
}

main();
